class Solution:
    def longestNiceSubstring(self, s):
        n = len(s)
        best = ''
        for i in range(n):
            chars = set()
            for j in range(i, n):
                chars.add(s[j])
                ok = True
                for c in chars:
                    if c.swapcase() not in chars:
                        ok = False
                        break
                if ok and (j - i + 1) > len(best):
                    best = s[i:j + 1]
        return best

