class Solution:
    def longestNiceSubstring(self, s):
        if len(s) < 2:
            return ''
        present = set(s)
        for i, ch in enumerate(s):
            if ch.swapcase() not in present:
                left = self.longestNiceSubstring(s[:i])
                right = self.longestNiceSubstring(s[i + 1:])
                return left if len(left) >= len(right) else right
        return s

